  try {
    const customer = await autumn.customers.getOrCreate({
      customerId: "user_test_001",
      name: "Alice Testuser",
      email: "alice@example.com"
    });
    console.log(JSON.stringify(customer, null, 2));
  } catch (error) {
    console.error("Error creating customer:", error);
    process.exit(1);
  }
}

main();

